#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

typedef float fp;

__kernel void extract_kernel(long d_Ne, __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            int d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks_work_size) {
    (void)d_Ne;
    (void)blocks_work_size;

    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int lsz = (int)get_local_size(0);

    if (tx == 0) {
        int start = bx * lsz;
        if (start < d_no) {
            int end = start + lsz;
            if (end > d_no) end = d_no;

            fp sum = 0.0f;
            fp sum2 = 0.0f;
            for (int i = start; i < end; i++) {
                int idx = i * d_mul;
                sum += d_sums[idx];
                sum2 += d_sums2[idx];
            }

            int out_idx = bx * d_mul * lsz;
            d_sums[out_idx] = sum;
            d_sums2[out_idx] = sum2;
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *dN,
                          __global fp *dS,
                          __global fp *dW,
                          __global fp *dE,
                          fp q0sqr,
                          __global fp *c,
                          __global fp *I) {
    (void)lambda;
    int ei = (int)get_global_id(0);
    if ((long)ei < Ne) {
        int row = ei / Nc;
        int col = ei % Nc;

        fp Jc = I[ei];

        int n_idx = iN[row] * Nc + col;
        int s_idx = iS[row] * Nc + col;
        int w_idx = row * Nc + jW[col];
        int e_idx = row * Nc + jE[col];

        fp d_n = I[n_idx] - Jc;
        fp d_s = I[s_idx] - Jc;
        fp d_w = I[w_idx] - Jc;
        fp d_e = I[e_idx] - Jc;

        fp G2 = (d_n * d_n + d_s * d_s + d_w * d_w + d_e * d_e) / (Jc * Jc);
        fp L = (d_n + d_s + d_w + d_e) / Jc;

        fp num = (fp)0.5f * G2 - (fp)0.0625f * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c_val = (fp)1.0f / ((fp)1.0f + den);

        if (c_val < (fp)0.0f) c_val = (fp)0.0f;
        else if (c_val > (fp)1.0f) c_val = (fp)1.0f;

        dN[ei] = d_n;
        dS[ei] = d_s;
        dW[ei] = d_w;
        dE[ei] = d_e;
        c[ei] = c_val;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *dN,
                           __global fp *dS,
                           __global fp *dW,
                           __global fp *dE,
                           __global fp *c,
                           __global fp *I) {
    (void)Nr;
    (void)iN;
    (void)jW;

    int ei = (int)get_global_id(0);
    if ((long)ei < Ne) {
        int row = ei / Nc;
        int col = ei % Nc;

        fp cN = c[ei];
        fp cS = c[iS[row] * Nc + col];
        fp cW = c[ei];
        fp cE = c[row * Nc + jE[col]];

        fp D = cN * dN[ei] + cS * dS[ei] + cW * dW[ei] + cE * dE[ei];
        I[ei] = I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne, __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
